import React, { useState, useEffect } from 'react';
import {
  Box,
  Typography,
  Paper,
  Button,
  Divider,
  CircularProgress,
  List,
  ListItem,
  ListItemText,
  ListItemIcon,
  IconButton,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
  InputAdornment,
  Chip,
  alpha,
  useTheme,
  Tab,
  Tabs
} from '@mui/material';
import {
  AccountBalanceWallet,
  AddCircleOutline,
  ArrowUpward,
  ArrowDownward,
  Receipt,
  History,
  KeyboardArrowRight,
  Close,
  AttachMoney,
  CreditCard,
  LocalAtm
} from '@mui/icons-material';
import { styled } from '@mui/material/styles';
import { motion } from 'framer-motion';
import { format } from 'date-fns';
import { ru } from 'date-fns/locale';
import { PaymentMethod } from '../types/payment';
import PaymentMethodSelector from '../components/PaymentMethodSelector';
import { PaymentProcessorService } from '../services/payment/PaymentProcessorService';
import { useFirebase } from '../context/FirebaseContext';

// Стилизованные компоненты
const WalletCard = styled(Paper)(({ theme }) => ({
  padding: theme.spacing(3),
  borderRadius: theme.spacing(3),
  background: `linear-gradient(135deg, ${theme.palette.primary.main} 0%, ${theme.palette.primary.dark} 100%)`,
  color: theme.palette.common.white,
  position: 'relative',
  overflow: 'hidden',
  boxShadow: '0 10px 20px rgba(0, 0, 0, 0.1)',
  marginBottom: theme.spacing(3),
}));

const BalanceText = styled(Typography)(({ theme }) => ({
  fontSize: '2.2rem',
  fontWeight: 700,
  marginBottom: theme.spacing(0.5),
}));

const CardPattern = styled(Box)(({ theme }) => ({
  position: 'absolute',
  bottom: 0,
  right: 0,
  width: '60%',
  height: '100%',
  background: 'radial-gradient(circle at 70% 50%, rgba(255,255,255,0.15) 0%, rgba(255,255,255,0) 70%)',
  zIndex: 0,
}));

const CardCircle = styled(Box)(({ theme }) => ({
  position: 'absolute',
  top: '-50px',
  right: '-50px',
  width: '150px',
  height: '150px',
  borderRadius: '50%',
  background: 'rgba(255,255,255,0.1)',
  zIndex: 0,
}));

const CardCircleSmall = styled(Box)(({ theme }) => ({
  position: 'absolute',
  bottom: '-30px',
  left: '20px',
  width: '100px',
  height: '100px',
  borderRadius: '50%',
  background: 'rgba(255,255,255,0.05)',
  zIndex: 0,
}));

const ActionButton = styled(Button)(({ theme }) => ({
  borderRadius: theme.spacing(6),
  padding: theme.spacing(1, 3),
  fontWeight: 600,
  textTransform: 'none',
  boxShadow: '0 4px 10px rgba(0,0,0,0.1)',
  '&:hover': {
    boxShadow: '0 6px 15px rgba(0,0,0,0.15)',
  }
}));

const TransactionCard = styled(Paper)(({ theme }) => ({
  marginBottom: theme.spacing(2),
  borderRadius: theme.spacing(2),
  overflow: 'hidden',
  boxShadow: 'none',
  border: `1px solid ${alpha(theme.palette.divider, 0.1)}`,
  '&:hover': {
    boxShadow: '0 4px 12px rgba(0,0,0,0.05)',
    borderColor: alpha(theme.palette.primary.main, 0.1),
  }
}));

const StatusChip = styled(Chip)(({ theme }) => ({
  borderRadius: theme.spacing(1),
  fontSize: '0.75rem',
  height: 24,
}));

// Интерфейсы для типизации
interface Transaction {
  id: string;
  type: 'deposit' | 'purchase';
  amount: number;
  status: 'completed' | 'pending' | 'failed';
  date: Date;
  description: string;
  paymentMethod?: PaymentMethod;
}

const WalletPage: React.FC = () => {
  const theme = useTheme();
  const { user } = useFirebase();
  const [balance, setBalance] = useState<number>(0);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [loading, setLoading] = useState<boolean>(true);
  const [openTopupDialog, setOpenTopupDialog] = useState<boolean>(false);
  const [topupAmount, setTopupAmount] = useState<string>('');
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>('yoomoney');
  const [isProcessingPayment, setIsProcessingPayment] = useState<boolean>(false);
  const [paymentError, setPaymentError] = useState<string | null>(null);
  const [tabValue, setTabValue] = useState<number>(0);

  // Загружаем баланс и транзакции
  useEffect(() => {
    const fetchWalletData = async () => {
      try {
        setLoading(true);
        
        // Здесь в реальном приложении мы бы загружали данные из Firebase
        // В этом примере используем моковые данные
        await new Promise(resolve => setTimeout(resolve, 1000));
        
        setBalance(5000);
        
        const mockTransactions: Transaction[] = [
          {
            id: '1',
            type: 'deposit',
            amount: 1000,
            status: 'completed',
            date: new Date(2025, 3, 20, 12, 30),
            description: 'Пополнение баланса',
            paymentMethod: 'yoomoney'
          },
          {
            id: '2',
            type: 'purchase',
            amount: 500,
            status: 'completed',
            date: new Date(2025, 3, 15, 10, 15),
            description: 'Покупка билета на розыгрыш BMW X5'
          },
          {
            id: '3',
            type: 'deposit',
            amount: 2000,
            status: 'completed',
            date: new Date(2025, 3, 10, 9, 45),
            description: 'Пополнение баланса',
            paymentMethod: 'telegram_wallet'
          },
          {
            id: '4',
            type: 'purchase',
            amount: 1500,
            status: 'completed',
            date: new Date(2025, 3, 5, 15, 20),
            description: 'Покупка билетов на розыгрыш Mercedes-Benz GLE'
          },
          {
            id: '5',
            type: 'deposit',
            amount: 3000,
            status: 'pending',
            date: new Date(),
            description: 'Пополнение баланса',
            paymentMethod: 'yoomoney'
          }
        ];
        
        setTransactions(mockTransactions);
      } catch (error) {
        console.error('Error fetching wallet data:', error);
      } finally {
        setLoading(false);
      }
    };
    
    fetchWalletData();
  }, [user]);

  // Обработчики для диалога пополнения
  const handleOpenTopupDialog = () => {
    setOpenTopupDialog(true);
    setTopupAmount('');
    setPaymentError(null);
  };

  const handleCloseTopupDialog = () => {
    setOpenTopupDialog(false);
  };

  const handlePaymentMethodChange = (method: PaymentMethod) => {
    setPaymentMethod(method);
  };

  const handleProcessPayment = async () => {
    if (!topupAmount || isNaN(parseFloat(topupAmount)) || parseFloat(topupAmount) <= 0) {
      setPaymentError('Пожалуйста, введите корректную сумму');
      return;
    }
    
    setIsProcessingPayment(true);
    setPaymentError(null);
    
    try {
      const amount = parseFloat(topupAmount);
      const result = await PaymentProcessorService.processPayment(
        paymentMethod,
        amount,
        'Пополнение баланса',
        user?.uid,
        { operation: 'wallet_topup' }
      );
      
      if (!result.success) {
        setPaymentError(result.error || 'Ошибка при инициализации платежа');
        setIsProcessingPayment(false);
      }
      // Для успешных платежей перенаправление происходит в самом сервисе processPayment
      
    } catch (error) {
      console.error('Payment error:', error);
      setPaymentError('Произошла ошибка при обработке платежа');
      setIsProcessingPayment(false);
    }
  };

  // Предопределенные суммы для быстрого пополнения
  const quickAmounts = [500, 1000, 3000, 5000];

  // Обработчик изменения вкладки
  const handleTabChange = (event: React.SyntheticEvent, newValue: number) => {
    setTabValue(newValue);
  };

  // Фильтрация транзакций в зависимости от выбранной вкладки
  const filteredTransactions = tabValue === 0 
    ? transactions 
    : tabValue === 1 
      ? transactions.filter(t => t.type === 'deposit')
      : transactions.filter(t => t.type === 'purchase');

  if (loading) {
    return (
      <Box sx={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '50vh' }}>
        <CircularProgress />
      </Box>
    );
  }

  return (
    <Box sx={{ pb: 6 }}>
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.4 }}
      >
        <Typography variant="h5" fontWeight={700} sx={{ mb: 3, display: 'flex', alignItems: 'center' }}>
          <AccountBalanceWallet sx={{ mr: 1, color: 'primary.main' }} />
          Кошелек
        </Typography>
        
        <WalletCard>
          <CardPattern />
          <CardCircle />
          <CardCircleSmall />
          <Box sx={{ position: 'relative', zIndex: 1 }}>
            <Typography variant="body2" sx={{ opacity: 0.9, mb: 0.5 }}>
              Баланс
            </Typography>
            <BalanceText variant="h4">
              {balance.toLocaleString()} ₽
            </BalanceText>
            <Box sx={{ display: 'flex', gap: 2, mt: 3 }}>
              <ActionButton
                variant="contained"
                color="inherit"
                startIcon={<AddCircleOutline />}
                onClick={handleOpenTopupDialog}
                sx={{ 
                  bgcolor: 'rgba(255,255,255,0.2)',
                  '&:hover': { bgcolor: 'rgba(255,255,255,0.3)' }
                }}
              >
                Пополнить
              </ActionButton>
              <ActionButton
                variant="outlined"
                startIcon={<History />}
                sx={{ 
                  color: 'white', 
                  borderColor: 'rgba(255,255,255,0.3)',
                  '&:hover': { borderColor: 'rgba(255,255,255,0.5)' } 
                }}
                onClick={() => setTabValue(0)}
              >
                История
              </ActionButton>
            </Box>
          </Box>
        </WalletCard>
        
        <Box sx={{ mb: 3 }}>
          <Tabs 
            value={tabValue} 
            onChange={handleTabChange}
            variant="fullWidth"
            sx={{ 
              mb: 3,
              '& .MuiTab-root': {
                fontWeight: 600,
                fontSize: '0.9rem',
                textTransform: 'none',
              }
            }}
          >
            <Tab icon={<History />} label="Все" iconPosition="start" />
            <Tab icon={<ArrowUpward />} label="Пополнения" iconPosition="start" />
            <Tab icon={<ArrowDownward />} label="Покупки" iconPosition="start" />
          </Tabs>
        </Box>
        
        {filteredTransactions.length > 0 ? (
          <List sx={{ p: 0 }}>
            {filteredTransactions.map((transaction) => (
              <TransactionCard key={transaction.id}>
                <ListItem 
                  secondaryAction={
                    <IconButton edge="end">
                      <KeyboardArrowRight />
                    </IconButton>
                  }
                >
                  <ListItemIcon>
                    {transaction.type === 'deposit' ? (
                      <Box 
                        sx={{ 
                          bgcolor: alpha(theme.palette.success.main, 0.1), 
                          p: 1, 
                          borderRadius: 2,
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center'
                        }}
                      >
                        <ArrowUpward sx={{ color: 'success.main' }} />
                      </Box>
                    ) : (
                      <Box 
                        sx={{ 
                          bgcolor: alpha(theme.palette.info.main, 0.1), 
                          p: 1, 
                          borderRadius: 2,
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center'
                        }}
                      >
                        <Receipt sx={{ color: 'info.main' }} />
                      </Box>
                    )}
                  </ListItemIcon>
                  <ListItemText
                    primary={transaction.description}
                    secondary={
                      <Box sx={{ display: 'flex', alignItems: 'center', flexWrap: 'wrap', gap: 1, mt: 0.5 }}>
                        <Box component="span" sx={{ color: theme.palette.text.secondary, fontSize: '0.875rem' }}>
                          {format(transaction.date, 'd MMM yyyy, HH:mm', { locale: ru })}
                        </Box>
                        <StatusChip 
                          size="small" 
                          label={
                            transaction.status === 'completed' ? 'Выполнено' :
                            transaction.status === 'pending' ? 'В обработке' :
                            'Ошибка'
                          }
                          color={
                            transaction.status === 'completed' ? 'success' :
                            transaction.status === 'pending' ? 'warning' :
                            'error'
                          }
                          variant="filled"
                        />
                        {transaction.paymentMethod && (
                          <Chip 
                            size="small" 
                            label={
                              transaction.paymentMethod === 'yoomoney' ? 'Карта' : 
                              'Telegram'
                            }
                            variant="outlined"
                            sx={{ height: 24, fontSize: '0.75rem' }}
                          />
                        )}
                      </Box>
                    }
                    sx={{ mr: 2 }}
                  />
                  <Typography 
                    variant="subtitle1" 
                    fontWeight={600} 
                    color={transaction.type === 'deposit' ? 'success.main' : 'info.main'}
                  >
                    {transaction.type === 'deposit' ? '+' : '-'}{transaction.amount.toLocaleString()} ₽
                  </Typography>
                </ListItem>
              </TransactionCard>
            ))}
          </List>
        ) : (
          <Box sx={{ textAlign: 'center', py: 6 }}>
            <Typography variant="body1" color="text.secondary">
              Нет транзакций
            </Typography>
          </Box>
        )}
      </motion.div>
      
      {/* Диалог пополнения баланса */}
      <Dialog
        open={openTopupDialog}
        onClose={handleCloseTopupDialog}
        PaperProps={{
          sx: {
            borderRadius: 3,
            maxWidth: 'sm',
            width: '100%',
          },
        }}
      >
        <DialogTitle sx={{ 
          display: 'flex', 
          alignItems: 'center', 
          justifyContent: 'space-between',
          pb: 1
        }}>
          <Typography variant="h6" component="div" sx={{ fontWeight: 600 }}>
            Пополнение баланса
          </Typography>
          <IconButton onClick={handleCloseTopupDialog} size="small">
            <Close />
          </IconButton>
        </DialogTitle>
        
        <DialogContent dividers>
          <Box sx={{ mb: 3 }}>
            <Typography variant="body1" sx={{ mb: 2 }}>
              Введите сумму пополнения:
            </Typography>
            
            <TextField
              fullWidth
              variant="outlined"
              label="Сумма"
              placeholder="Например, 1000"
              value={topupAmount}
              onChange={(e) => setTopupAmount(e.target.value.replace(/[^0-9.]/g, ''))}
              InputProps={{
                startAdornment: (
                  <InputAdornment position="start">
                    <AttachMoney />
                  </InputAdornment>
                ),
                endAdornment: (
                  <InputAdornment position="end">₽</InputAdornment>
                ),
              }}
              sx={{ mb: 2 }}
            />
            
            <Typography variant="body2" sx={{ mb: 1 }}>
              Быстрые суммы:
            </Typography>
            
            <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 1, mb: 3 }}>
              {quickAmounts.map((amount) => (
                <Chip
                  key={amount}
                  label={`${amount.toLocaleString()} ₽`}
                  onClick={() => setTopupAmount(amount.toString())}
                  clickable
                  color="primary"
                  variant={topupAmount === amount.toString() ? 'filled' : 'outlined'}
                  sx={{ borderRadius: 2, py: 2.5, px: 1 }}
                />
              ))}
            </Box>
            
            <Divider sx={{ my: 3 }} />
            
            <PaymentMethodSelector
              selectedMethod={paymentMethod}
              onMethodChange={handlePaymentMethodChange}
            />
            
            {paymentError && (
              <Box sx={{ mt: 2, p: 2, bgcolor: alpha(theme.palette.error.main, 0.1), borderRadius: 2 }}>
                <Typography color="error" variant="body2">
                  {paymentError}
                </Typography>
              </Box>
            )}
          </Box>
        </DialogContent>
        
        <DialogActions sx={{ p: 2 }}>
          <Button
            onClick={handleCloseTopupDialog}
            color="inherit"
            disabled={isProcessingPayment}
          >
            Отмена
          </Button>
          <Button
            variant="contained"
            color="primary"
            onClick={handleProcessPayment}
            disabled={isProcessingPayment || !topupAmount || parseFloat(topupAmount) <= 0}
            startIcon={isProcessingPayment ? <CircularProgress size={20} color="inherit" /> : null}
          >
            {isProcessingPayment ? 'Обработка...' : 'Пополнить'}
          </Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
};

export default WalletPage;
